return [{
  json: {
    source_post_url: "https://www.instagram.com/reel/REPLACE_WITH_REAL_CODE/",
    target_ad_account_id: "21111111-1111-4111-8111-111111111113",
    requested_daily_budget: 10,
    destination_type: "whatsapp",
    execution_mode: "dry_run"
  }
}];

const input = $json.body ?? $json;

const ACCOUNT_MAP = {
  "0c8b9c6a-4b0e-4424-9fed-7cc2771777e1": "act_1264530092507896",
  "21111111-1111-4111-8111-111111111112": "act_1626945551688947",
  "21111111-1111-4111-8111-111111111113": "act_925213410124697"
};

const ORGANIZATION_ID = "11111111-1111-4111-8111-111111111111";
const MIN_BUDGET = 5;
const MAX_BUDGET = 25;

function normalizeUrl(value) {
  if (typeof value !== "string") return "";
  return value.trim().replace(/^=+/, "").replace(/[?#].*$/, "").replace(/\/+$/, "/");
}

function classify(url, providedPlatform = null, providedType = null) {
  if (providedPlatform === 'instagram' || providedPlatform === 'facebook') {
    return {
      valid: true,
      platform: providedPlatform,
      content_type: providedType ?? null
    };
  }

  const lower = url.toLowerCase();

  if (/facebook\.com\/share\//.test(lower) || /fb\.watch\//.test(lower)) {
    return {
      valid: false,
      error_code: "SHARE_URL_NOT_SUPPORTED",
      error_message: "استخدم الرابط الأصلي للمنشور أو الريل، وليس رابط Facebook share المختصر."
    };
  }

  if (/instagram\.com\/(p|reel|reels|tv)\//.test(lower)) {
    const kind = /instagram\.com\/(reel|reels)\//.test(lower) ? "reel" : "post";
    return { valid: true, platform: "instagram", content_type: kind };
  }

  if (
    /facebook\.com\/.+\/posts\//.test(lower) ||
    /facebook\.com\/permalink\.php/.test(lower) ||
    /facebook\.com\/.+\/videos\//.test(lower) ||
    /facebook\.com\/reel\//.test(lower) ||
    /facebook\.com\/watch/.test(lower)
  ) {
    const kind =
      (/\/reel\//.test(lower) || /\/videos\//.test(lower) || /\/watch/.test(lower))
        ? "reel"
        : "post";

    return { valid: true, platform: "facebook", content_type: kind };
  }

  return {
    valid: false,
    error_code: "UNSUPPORTED_URL",
    error_message: "الرابط غير معروف. استخدم رابطًا أصليًا لمنشور أو Reel من Facebook أو Instagram."
  };
}

const contentLibraryId = String(input.content_library_id ?? "").trim();
const contentLibraryError = input._content_library_error ?? null;
const url = normalizeUrl(input.source_post_url);
const targetAdAccountId = String(input.target_ad_account_id ?? "").trim();

const budgetRaw = input.requested_daily_budget;
const budget =
  budgetRaw === null || budgetRaw === undefined || budgetRaw === ""
    ? null
    : Number(budgetRaw);

const errors = [];

if (contentLibraryError) {
  errors.push(contentLibraryError);
}

if (!contentLibraryId && !url) {
  errors.push({
    code: "MISSING_CONTENT_SOURCE",
    message: "يجب تحديد content_library_id أو source_post_url."
  });
}

if (contentLibraryId && !url) {
  errors.push({
    code: "CONTENT_PERMALINK_MISSING",
    message: "المحتوى المحدد لا يحتوي رابط permalink صالحًا."
  });
}

if (!ACCOUNT_MAP[targetAdAccountId]) {
  errors.push({
    code: "INVALID_AD_ACCOUNT",
    message: "الحساب الإعلاني غير معروف أو غير مدعوم."
  });
}

if (
  budget !== null &&
  (!Number.isFinite(budget) || budget < MIN_BUDGET || budget > MAX_BUDGET)
) {
  errors.push({
    code: "INVALID_BUDGET",
    message: `الميزانية اليومية يجب أن تكون بين ${MIN_BUDGET}$ و${MAX_BUDGET}$.`
  });
}

const classified = url
  ? classify(
      url,
      input.source_platform ?? null,
      input.content_context?.media_type ?? null
    )
  : { valid: false };

if (url && !classified.valid) {
  errors.push({
    code: classified.error_code,
    message: classified.error_message
  });
}

const destinationType = String(
  input.destination_type ?? "whatsapp"
).toLowerCase();

if (!["whatsapp", "messenger", "website"].includes(destinationType)) {
  errors.push({
    code: "INVALID_DESTINATION",
    message: "destination_type يجب أن يكون whatsapp أو messenger أو website."
  });
}

const executionMode = String(
  input.execution_mode ?? "dry_run"
).toLowerCase();

if (!["dry_run", "review", "live"].includes(executionMode)) {
  errors.push({
    code: "INVALID_EXECUTION_MODE",
    message: "execution_mode يجب أن يكون dry_run أو review أو live."
  });
}

const placements = String(
  input.placements ?? "advantage_plus"
).toLowerCase();

if (!["advantage_plus", "facebook_only", "instagram_only"].includes(placements)) {
  errors.push({
    code: "INVALID_PLACEMENTS",
    message: "placements يجب أن يكون advantage_plus أو facebook_only أو instagram_only."
  });
}

const now = new Date().toISOString();

const idempotencyBase = [
  ORGANIZATION_ID,
  targetAdAccountId,
  contentLibraryId || url,
  destinationType,
  executionMode
].join("|");

let hash = 0;
for (let i = 0; i < idempotencyBase.length; i++) {
  hash = ((hash << 5) - hash) + idempotencyBase.charCodeAt(i);
  hash |= 0;
}

const idempotencyKey =
  `ws02-${Math.abs(hash)}-${now.slice(0,10)}`;

const alreadyResolved =
  contentLibraryId &&
  input.resolver_status === "resolved" &&
  Boolean(input.source_post_id || input.instagram_media_id);

const requestPayload = {
  original_input: input,
  detected_content_type: classified.content_type,
  received_at: now,
  placement_preference: placements,
  resolver_status: alreadyResolved ? "resolved" : "pending",
  resolver_method: alreadyResolved ? "content_library" : null,
  content_library_id: contentLibraryId || null,
  source_post_id: input.source_post_id ?? null,
  instagram_media_id: input.instagram_media_id ?? null,
  page_id: input.page_id ?? null,
  object_story_id: input.object_story_id ?? null,
  content_context: input.content_context ?? null,
  resolved_at: alreadyResolved ? now : null
};

return [{
  json: {
    ok: errors.length === 0,
    http_status: errors.length === 0 ? 202 : 400,
    errors,
    record: errors.length === 0
      ? {
          organization_id: ORGANIZATION_ID,
          target_ad_account_id: targetAdAccountId,
          target_meta_account_id: ACCOUNT_MAP[targetAdAccountId],
          source_platform: classified.platform,
          source_post_url: url,
          destination_type: destinationType,
          execution_mode: executionMode,
          status: "draft",
          requested_daily_budget: budget,
          idempotency_key: idempotencyKey,
          request_payload: requestPayload
        }
      : null,
    next_step: alreadyResolved ? "strategy" : "resolver"
  }
}];

const saved = Array.isArray($json)
  ? ($json[0] ?? null)
  : ($json?.data?.[0] ?? $json);

if (!saved?.id) {
  return [{
    json: {
      ok: false,
      http_status: 502,
      error: "INTAKE_SAVE_RESPONSE_INVALID",
      message: "تم إرسال الطلب إلى Supabase لكن لم يتم إرجاع request_id صالح."
    }
  }];
}

const payload = saved.request_payload ?? {};
const resolved = payload.resolver_status === 'resolved';

return [{
  json: {
    ok: true,
    http_status: 202,
    status: saved.status ?? "draft",
    id: saved.id,
    request_id: saved.id,
    source_platform: saved.source_platform ?? null,
    source_post_url: saved.source_post_url ?? null,
    target_ad_account_id: saved.target_ad_account_id ?? null,
    target_meta_account_id: saved.target_meta_account_id ?? null,
    destination_type: saved.destination_type ?? null,
    execution_mode: saved.execution_mode ?? null,
    resolver_status: payload.resolver_status ?? null,
    next_step: resolved ? "strategy" : "resolver",
    content_library_id: payload.content_library_id ?? null,
    source_post_id: payload.source_post_id ?? null,
    instagram_media_id: payload.instagram_media_id ?? null,
    page_id: payload.page_id ?? null,
    message: resolved
      ? "تم حفظ طلب الحملة من مكتبة المحتوى وهو جاهز مباشرة لتوليد الاستراتيجية."
      : "تم حفظ طلب إنشاء الحملة كمسودة. الخطوة التالية هي حل معرّف Existing Post."
  }
}];

return [{
  json: {
    ok: false,
    http_status: 400,
    error: "VALIDATION_FAILED",
    details: Array.isArray($json.errors) ? $json.errors : [],
    message: "لم يتم حفظ الطلب لأن البيانات غير صالحة."
  }
}];

const input = $json.body ?? $json;

return [{
  json: {
    input,
    content_library_id: String(input.content_library_id ?? '').trim(),
    has_content_library_id: Boolean(String(input.content_library_id ?? '').trim())
  }
}];

const input = $('Normalize Intake Input').first().json.input;
const raw = $json;

let content = null;
if (Array.isArray(raw)) {
  content = raw[0] ?? null;
} else if (Array.isArray(raw?.data)) {
  content = raw.data[0] ?? null;
} else if (raw && typeof raw === 'object' && raw.id) {
  content = raw;
}

if (!content) {
  return [{
    json: {
      ...input,
      _content_library_error: {
        code: 'CONTENT_LIBRARY_ITEM_NOT_FOUND',
        message: 'لم يتم العثور على المحتوى المحدد داخل مكتبة المحتوى.'
      }
    }
  }];
}

return [{
  json: {
    ...input,
    content_library_id: content.id,
    source_post_url: content.permalink,
    source_platform: content.platform,
    source_post_id: content.meta_post_id,
    instagram_media_id: content.instagram_media_id,
    page_id: content.page_id,
    content_context: {
      caption: content.caption ?? null,
      media_type: content.content_type ?? content.media_type ?? null,
      thumbnail_url: content.thumbnail_url ?? null,
      media_url: content.media_url ?? null,
      permalink: content.permalink ?? null,
      created_time: content.created_time ?? null,
      likes_count: Number(content.likes_count ?? 0),
      comments_count: Number(content.comments_count ?? 0),
      shares_count: Number(content.shares_count ?? 0)
    },
    resolver_status: 'resolved',
    resolver_method: 'content_library'
  }
}];
